var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"겨우 세 명인데 뭐하는 거야! 똑바로 안 해!?","JPN":"たった3人しかいねえのに、何してんだ！　ちゃんとやれ！！","ENG":"What are you doing?! There are only three of them! Keep it together!","TWN":"他們才三個人而已！給我認真一點！！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"이, 이건 얘기가 다르잖아요, 형님!","JPN":"こ、これは話が違うっしょ、兄貴！","ENG":"Th-this isn't what I signed up for!","TWN":"這跟說好的不一樣啊！大哥！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"분명히 뜨내기 태스크포스라고……!","JPN":"確かにわか作りのタスクフォースだって……！","ENG":"I thought they were some rookie TASKFORCE–?!","TWN":"你不是說他們是三流特遣勢力……！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"UNDER_CHARADE_NPC_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_B","text":{"KOREA":"으악! 내 눈!!","JPN":"うわっ！　目が！！","ENG":"Aargh! My eye!!","TWN":"啊啊！我的眼睛！！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"나원, 저것들은 양심도 없나?","JPN":"まったく、あいつら良心ってものがないのかね？","ENG":"Egh, don't they feel any shame?","TWN":"那些傢伙的良心不會痛嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"신나게 실탄 쏘던 것들이 어딜 모의탄 맞고 엄살이야?","JPN":"実弾撃ってたくせに、模擬弾に当たって騒ぐなんてさ。","ENG":"They were shooting bullets at us, and now they're crying about being hit by rubber bullets?","TWN":"自己開槍開得那麼開心，被漆彈打到而已在那邊哀哀叫？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어차피 우리 목표는 수송기 탈환이에요. 일일이 상대해줄 필요 없어요.","JPN":"私たちの狙いは輸送船の奪還よ。いちいち相手してあげる必要なんかないわ。","ENG":"Our objective is to take back the aircraft. We don't need to deal with all of them.","TWN":"反正我們的目的是奪回運輸機，不需要見一個打一個。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"수송기까지 거의 다 왔어요!","JPN":"輸送船まであと少しです！","ENG":"I've almost reached the aircraft!","TWN":"快到運輸機了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이제 탑승만 하면…….","JPN":"後は搭乗さえできれば……","ENG":"I just need to get on it...","TWN":"趕快搭上去就……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"잠깐! 장난은 거기까지다!","JPN":"待った！　お遊びはここまでだ！","ENG":"Hold it right there! Playtime's over!","TWN":"想得美！遊戲結束了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HEMSWORTH_NPC_SUPPLEMENT_NULL","text":{"KOREA":"……윽!","JPN":"……うっ！","ENG":"...Ngh!","TWN":"……唔！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"음? 저자는……?","JPN":"ん？　あの者は……？","ENG":"Hmm? That's...?","TWN":"嗯？他是……？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"후우, 생포하는 데 고생 좀 했지. 늙다리 주제에 주먹은 더럽게 매워 가지곤.","JPN":"ふう、生け捕りするのにちょっと苦労したぜ。老いぼれのくせに拳がやたら強くてな。","ENG":"Phew. Took longer than expected to capture him alive. He's got one mean punch for an old man.","TWN":"呼，費了一番勁才活捉到他，這老傢伙拳頭很硬呢！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"자, 아무튼 분위기 파악했으면 당장 수송기에서 떨어져.","JPN":"さあ、とにかく空気読んだなら、今すぐ輸送船から離れるんだ。","ENG":"Now, step away from the aircraft if you know what's good for you.","TWN":"總之，勸你們搞清楚狀況，趕快從運輸機上下來。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"그렇지 않으면 이 노인네의……","JPN":"じゃないと、この老人の……","ENG":"Or else, this old man is gonna–","TWN":"否則這個老傢伙……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"UNDER_CHARADE_NPC_A","text":{"KOREA":"으악! 무, 무슨 짓거리야! 아프잖아!","JPN":"うわっ！　な、何しやがる！　痛いじゃねえか！","ENG":"Aaargh! W-what was that for?! That hurt!","TWN":"呃啊！你，你做什麼！很痛欸！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"UNDER_CHARADE_NPC_A","face":"UNIT_IDLE"},"R":{"char_id":"HEMSWORTH_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};